const body = $input.first().json.body || $input.first().json;

// Valid sequence types
const validTypes = ['welcome', 'post_purchase', 'lead_magnet', 'newsletter', 'winback'];
const sequenceType = body.sequence_type || 'welcome';

if (!validTypes.includes(sequenceType)) {
  return [{ json: { error: true, message: `Invalid sequence_type. Valid: ${validTypes.join(', ')}` } }];
}

return [{ json: {
  sequence_type: sequenceType,
  brand_name: 'ClearStack Studio',
  brand_tagline: 'Tools that clear your mind and build your future.',
  brand_url: 'https://clearstackstudio.com',
  brand_color: '#1B2A4A',
  accent_color: '#C9A84C',
  from_name: 'ClearStack Studio',
  from_email: 'hello@clearstackstudio.com',
  reply_to: 'hello@clearstackstudio.com',
  tone: 'Professional but warm. Like a successful entrepreneur friend. Direct, specific, zero fluff.',
  forbidden_phrases: ['game-changer', 'leverage', 'synergy', 'crushing it', 'hustle hard', 'delve into', 'in this day and age'],
  product_name: body.product_name || '',
  product_url: body.product_url || '',
  product_price: body.product_price || '',
  product_description: body.product_description || '',
  lead_magnet_url: body.lead_magnet_url || 'https://clearstackstudio.com/free',
  lead_magnet_name: body.lead_magnet_name || 'Free Productivity Starter Kit',
  subscriber_segment: body.subscriber_segment || 'general',
  unsubscribe_placeholder: '{{unsubscribe}}',
  _prepared: true
}}];

values.content:
=Write a complete 5-email post-purchase sequence for:

Brand: {{$json.brand_name}}
Product: {{$json.product_name}}
Product URL: {{$json.product_url}}
Product Price: ${{$json.product_price}}
Tone: {{$json.tone}}
Website: {{$json.brand_url}}

Sequence structure:
- Email 1 (Day 0, immediate): Purchase confirmation + download link + how to access
- Email 2 (Day 1): Quick-start guide — how to get the most from this product in 10 minutes
- Email 3 (Day 3): Related product suggestion (upsell — soft, helpful framing)
- Email 4 (Day 7): Review request — ask for Etsy/Google review (friendly, no pressure)
- Email 5 (Day 14): Exclusive returning customer offer — 15% off next purchase

Rules:
- Email 1 must include the download link prominently
- Email 4 review request: make it easy, provide direct link, explain why it helps
- Never be pushy — these are customers who already trust you
- Specific to the product — not generic 'digital product' copy

Respond ONLY with this JSON (same structure as welcome series):
{
  "sequence_name": "Post-Purchase — [product name]",
  "emails": [ { "email_number": 1, "send_delay_days": 0, "send_delay_hours": 0, "purpose": "...", "subject": "...", "preview_text": "...", "body_html": "...", "body_text": "...", "cta_text": "...", "cta_url": "...", "ps_line": "..." } ]
}

=Write a 3-email lead magnet delivery sequence for:

Brand: {{$json.brand_name}}
Lead magnet: {{$json.lead_magnet_name}}
Lead magnet URL: {{$json.lead_magnet_url}}
Related paid product: {{$json.product_name || 'productivity templates'}}
Product URL: {{$json.product_url || $json.brand_url}}
Tone: {{$json.tone}}

Sequence:
- Email 1 (Day 0): Deliver the freebie + one quick win they can get immediately
- Email 2 (Day 2): Related tip that builds on the freebie (pure value, no sell)
- Email 3 (Day 5): Natural bridge from freebie → paid product (helpful, not pushy)

Respond ONLY with this JSON:
{
  "sequence_name": "Lead Magnet — [freebie name]",
  "emails": [ { "email_number": 1, "send_delay_days": 0, "send_delay_hours": 0, "purpose": "...", "subject": "...", "preview_text": "...", "body_html": "...", "body_text": "...", "cta_text": "...", "cta_url": "...", "ps_line": "..." } ]
}

