// Universal parser for all sequence types
const raw = $input.first().json;
const context = $('⚙️ Validate + Build Email Context').first().json;

let sequenceData;
try {
  const content = raw?.message?.content || raw?.response || '';
  const match = content.match(/```json\n?([\s\S]*?)\n?```/) || content.match(/({[\s\S]*})/);
  sequenceData = JSON.parse((match ? match[1] || match[0] : content).trim());
} catch(e) {
  sequenceData = { error: true, message: e.message, emails: [] };
}

const emails = sequenceData.emails || (sequenceData.send_immediately ? [sequenceData] : []);

// Build Brevo-compatible email objects
const brevoEmails = emails.map((email, i) => {
  // Wrap body in full branded HTML template
  const fullHtml = `<!DOCTYPE html>
<html>
<head><meta charset="UTF-8"><meta name="viewport" content="width=device-width,initial-scale=1">
<style>
  body{margin:0;padding:0;background:#f4f4f4;font-family:Arial,sans-serif;}
  .wrapper{max-width:600px;margin:0 auto;background:#ffffff;}
  .header{background:linear-gradient(135deg,#1B2A4A,#2D4A7A);padding:28px 32px;}
  .header h1{color:white;margin:0;font-size:20px;font-weight:700;}
  .header p{color:rgba(255,255,255,0.7);margin:4px 0 0;font-size:13px;}
  .accent-bar{height:4px;background:#C9A84C;}
  .body{padding:32px;}
  .body p{color:#333;font-size:15px;line-height:1.7;margin:0 0 16px;}
  .body a{color:#1B2A4A;}
  .body strong{color:#1B2A4A;}
  .cta-wrap{text-align:center;margin:28px 0;}
  .cta{background:#1B2A4A;color:white!important;padding:14px 32px;border-radius:6px;text-decoration:none;font-weight:700;font-size:15px;display:inline-block;}
  .ps{color:#666;font-size:13px;border-top:1px solid #eee;padding-top:16px;margin-top:24px;}
  .footer{background:#f4f4f4;padding:20px 32px;text-align:center;}
  .footer p{color:#999;font-size:12px;margin:4px 0;}
  .footer a{color:#999;}
  ul{padding-left:20px;} li{margin:8px 0;font-size:15px;color:#333;line-height:1.6;}
</style>
</head>
<body>
<div class="wrapper">
  <div class="header">
    <h1>${context.brand_name}</h1>
    <p>${context.brand_tagline}</p>
  </div>
  <div class="accent-bar"></div>
  <div class="body">
    ${email.body_html || ''}
    ${email.cta_url ? `<div class="cta-wrap"><a class="cta" href="${email.cta_url}">${email.cta_text || 'View Now'}</a></div>` : ''}
    ${email.ps_line ? `<div class="ps">P.S. ${email.ps_line}</div>` : ''}
  </div>
  <div class="footer">
    <p>${context.brand_name} · <a href="${context.brand_url}">${context.brand_url.replace('https://', '')}</a></p>
    <p><a href="${context.unsubscribe_placeholder}">Unsubscribe</a></p>
  </div>
</div>
</body></html>`;

  return {
    email_number: email.email_number || i + 1,
    send_delay_days: email.send_delay_days || 0,
    send_delay_hours: email.send_delay_hours || 0,
    subject: email.subject || `Email from ${context.brand_name}`,
    preview_text: email.preview_text || '',
    html_content: fullHtml,
    text_content: email.body_text || email.body_html?.replace(/<[^>]+>/g, '') || '',
    purpose: email.purpose || '',
    cta_text: email.cta_text || '',
    cta_url: email.cta_url || ''
  };
});

return [{ json: {
  sequence_type: context.sequence_type,
  sequence_name: sequenceData.sequence_name || `${context.sequence_type} sequence`,
  email_count: brevoEmails.length,
  emails: brevoEmails,
  product_name: context.product_name,
  send_immediately: sequenceData.send_immediately || false,
  _ready_for_brevo: true
}}];
